// triggerBatchReport summarizes one batch trigger run. Errors are captured
// per-contact so a follow-up invocation can target only the failed ids
// without re-triggering successful ones.
type triggerBatchReport struct {
	TotalInput     int               `json:"total_input"`
	Triggered      int               `json:"triggered"`
	Errors         []triggerBatchErr `json:"errors"`
	DryRun         bool              `json:"dry_run,omitempty"`
	VerifySkipped  bool              `json:"verify_skipped,omitempty"`
	DogfoodSkipped bool              `json:"dogfood_skipped,omitempty"`
	Source         string            `json:"source,omitempty"`
}

type triggerBatchErr struct {
	ContactID string `json:"contact_id"`
	Err       string `json:"err"`
}

// readContactIDs ingests one-id-per-line input from r, skipping blank lines
// and `#`-prefixed comments so the input file can carry annotation without
// special tooling.
func readContactIDs(r io.Reader) ([]string, error) {
	var ids []string
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		ids = append(ids, line)
	}
	return ids, scanner.Err()
}

func newAutomationsTriggerBatchCmd(flags *rootFlags) *cobra.Command {
	var filePath string
	var rate float64

	cmd := &cobra.Command{
		Use:   "trigger-batch <automation_id>",
		Short: "Queue an automation for many contacts at a paced rate",
		Example: `  # Trigger an automation for a list of contact ids from stdin
  cat contact_ids.txt | emailoctopus-pp-cli automations trigger-batch c81c21ca-51cc-11f1-ad3e-ffeba75576ac

  # From a file at a different rate
  emailoctopus-pp-cli automations trigger-batch c81c21ca-51cc-11f1-ad3e-ffeba75576ac \
    --file contact_ids.txt --rate 5`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return cmd.Help()
			}
			automationID := args[0]
			// Validate UUID shape early so a typo or placeholder returns a
			// clear error instead of a "0 triggered" envelope that looks
			// like a successful no-op.
			if !store.IsUUID(automationID) {
				return usageErr(fmt.Errorf("automation_id %q is not a valid UUID", automationID))
			}

			var src io.Reader
			source := "stdin"
			if filePath != "" {
				f, err := os.Open(filePath)
				if err != nil {
					return fmt.Errorf("opening --file: %w", err)
				}
				defer f.Close()
				src = f
				source = filePath
			} else {
				src = cmd.InOrStdin()
			}

			ids, err := readContactIDs(src)
			if err != nil {
				return fmt.Errorf("reading contact ids: %w", err)
			}
			report := triggerBatchReport{TotalInput: len(ids), Source: source}

			if flags.dryRun {
				report.DryRun = true
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			if cliutil.IsVerifyEnv() {
				report.VerifySkipped = true
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			if cliutil.IsDogfoodEnv() {
				report.DogfoodSkipped = true
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			sleep := time.Duration(0)
			if rate > 0 {
				sleep = time.Duration(float64(time.Second) / rate)
			}

			path := "/automations/" + automationID + "/queue"
			for i, id := range ids {
				_, _, perr := c.Post(path, map[string]any{"contact_id": id})
				if perr != nil {
					report.Errors = append(report.Errors, triggerBatchErr{ContactID: id, Err: perr.Error()})
				} else {
					report.Triggered++
				}
				if (i+1)%10 == 0 {
					fmt.Fprintf(os.Stderr, "Triggered %d/%d…\n", report.Triggered, len(ids))
				}
				if i < len(ids)-1 && sleep > 0 {
					time.Sleep(sleep)
				}
			}
			return printJSONFiltered(cmd.OutOrStdout(), report, flags)
		},
	}

	cmd.Flags().StringVar(&filePath, "file", "", "Read contact ids from a file (one per line) instead of stdin")
	cmd.Flags().Float64Var(&rate, "rate", 8, "Max POST requests per second")
	return cmd
}
